$toolDefinition_ssl_expiry_monitor = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'ssl_expiry_monitor',
    'description' => 'Monitor SSL certificate expiry for multiple domains, persist results in SQLite, and report changes. Builds on ssl_cert_check\'s TLS inspection technique (stream_socket_client + capture_peer_cert + openssl_x509_parse) but adds: multi-domain batch checking, persistent SQLite storage with change detection, expiry alerts, and summary report generation. First unattended security monitoring capability in the ecosystem. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'domains' => 
        array (
          'type' => 'array',
          'description' => 'Array of domains to check (e.g. [\'google.com\',\'github.com\',\'php.net\']). If not provided, checks all stored domains in the database.',
          'items' => 
          array (
            'type' => 'string',
          ),
        ),
        'db_name' => 
        array (
          'type' => 'string',
          'description' => 'SQLite database filename in workspace for persistent storage. Default: \'ssl_monitor.sqlite\'.',
        ),
        'timeout' => 
