          'description' => '\'check\' — check all domains and store results. \'report\' — show latest results from DB. \'check_report\' — check and then generate report. \'add_domains\' — add domains to monitoring list without checking. \'remove_domain\' — remove a domain from monitoring. Default: \'check_report\'.',
        ),
        'warning_days' => 
