if (! function_exists('ssl_expiry_monitor')) {
    function ssl_expiry_monitor($domains = null, $db_name = null, $timeout = null, $port = null, $mode = null, $warning_days = null, $critical_days = null)
    {
            $domains = $domains ?? [];
            $db_name = $db_name ?? 'ssl_monitor.sqlite';
            $timeout = $timeout ?? 15;
            $port = $port ?? 443;
            $mode = $mode ?? 'check_report';
            $warning_days = $warning_days ?? 30;
            $critical_days = $critical_days ?? 7;

            $timeout = max(5, min(30, (int)$timeout));
            $port = max(1, min(65535, (int)$port));
            $warning_days = max(1, min(365, (int)$warning_days));
            $critical_days = max(1, min(min(365, $warning_days - 1), (int)$critical_days));

            $db_path = __DIR__ . '/../workspace/' . $db_name;

            // Initialize database
            try {
                $pdo = new PDO("sqlite:$db_path");
                $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $pdo->exec("CREATE TABLE IF NOT EXISTS ssl_checks (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    domain TEXT NOT NULL,
                    port INTEGER DEFAULT 443,
                    common_name TEXT,
                    issuer_org TEXT,
                    valid_from TEXT,
                    valid_to TEXT,
                    days_remaining INTEGER,
                    expired INTEGER DEFAULT 0,
                    san_count INTEGER DEFAULT 0,
                    sans TEXT,
                    signature_algo TEXT,
                    serial_number TEXT,
                    is_wildcard INTEGER DEFAULT 0,
                    connect_time_ms REAL,
                    status TEXT DEFAULT 'unknown',
                    error_message TEXT,
                    checked_at TEXT DEFAULT (datetime('now'))
                )");
                $pdo->exec("CREATE TABLE IF NOT EXISTS ssl_domains (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    domain TEXT NOT NULL UNIQUE,
                    port INTEGER DEFAULT 443,
                    label TEXT,
                    added_at TEXT DEFAULT (datetime('now')),
                    active INTEGER DEFAULT 1
                )");
            } catch (Exception $e) {
                return ['success' => false, 'error' => 'Database init failed: ' . $e->getMessage()];
            }

            $result = ['success' => true, 'mode' => $mode, 'db' => $db_name];

            // --- add_domains mode ---
            if ($mode === 'add_domains') {
                if (empty($domains)) {
                    return ['success' => false, 'error' => 'No domains provided to add.'];
                }
                $added = [];
                $errors = [];
                $stmt = $pdo->prepare("INSERT OR IGNORE INTO ssl_domains (domain, port) VALUES (?, ?)");
                foreach ($domains as $d) {
                    $d = trim(strtolower($d));
                    if (empty($d)) continue;
                    // Strip protocol
                    $d = preg_replace('#^https?://#', '', $d);
                    $d = preg_replace('#/.*$#', '', $d);
                    $d = preg_replace('#:\d+$#', '', $d);
                    try {
                        $stmt->execute([$d, $port]);
                        if ($stmt->rowCount() > 0) {
                            $added[] = $d;
                        }
                    } catch (Exception $e) {
                        $errors[] = $d . ': ' . $e->getMessage();
                    }
                }
                $result['added'] = $added;
                $result['errors'] = $errors;
                return $result;
            }

            // --- remove_domain mode ---
            if ($mode === 'remove_domain') {
                if (empty($domains)) {
                    return ['success' => false, 'error' => 'No domain specified to remove.'];
                }
                $removed = [];
                $stmt = $pdo->prepare("DELETE FROM ssl_domains WHERE domain = ?");
                foreach ($domains as $d) {
                    $d = trim(strtolower($d));
                    $d = preg_replace('#^https?://#', '', $d);
                    $d = preg_replace('#/.*$#', '', $d);
                    $d = preg_replace('#:\d+$#', '', $d);
                    $stmt->execute([$d]);
                    if ($stmt->rowCount() > 0) $removed[] = $d;
                }
                $result['removed'] = $removed;
                return $result;
            }

            // --- check mode (do the SSL checks) ---
            if (in_array($mode, ['check', 'check_report'])) {
                // Determine which domains to check
                $check_list = [];
                if (!empty($domains)) {
                    foreach ($domains as $d) {
                        $d = trim(strtolower($d));
                        $d = preg_replace('#^https?://#', '', $d);
                        $d = preg_replace('#/.*$#', '', $d);
                        $d = preg_replace('#:\d+$#', '', $d);
                        if (!empty($d)) $check_list[] = $d;
                    }
                } else {
                    // Get all active domains from DB
                    $stored = $pdo->query("SELECT domain, port FROM ssl_domains WHERE active = 1 ORDER BY domain");
                    foreach ($stored as $row) {
                        $check_list[] = $row['domain'];
                    }
                }

                if (empty($check_list)) {
                    $result['checks'] = [];
                    $result['message'] = 'No domains to check. Add domains with add_domains mode or pass domains array.';
                    if ($mode === 'check') return $result;
                    // Fall through to report
                } else {
                    $checks = [];
                    $checked_count = 0;
                    $error_count = 0;
                    $expiring_count = 0;
                    $expired_count = 0;

                    $insert_stmt = $pdo->prepare("INSERT INTO ssl_checks (domain, port, common_name, issuer_org, valid_from, valid_to, days_remaining, expired, san_count, sans, signature_algo, serial_number, is_wildcard, connect_time_ms, status, error_message) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");

                    foreach ($check_list as $check_domain) {
                        $domain_port = $port;
                        // Look up port from domains table
                        $dp = $pdo->prepare("SELECT port FROM ssl_domains WHERE domain = ?");
                        $dp->execute([$check_domain]);
                        $drow = $dp->fetch(PDO::FETCH_ASSOC);
                        if ($drow) $domain_port = (int)$drow['port'];

                        $checked_count++;

                        // Connect and check SSL cert
                        $context = stream_context_create([
                            'ssl' => [
                                'capture_peer_cert' => true,
                                'verify_peer' => false,
                                'verify_peer_name' => false,
                                'allow_self_signed' => true,
                            ]
                        ]);

                        $target = "ssl://{$check_domain}:{$domain_port}";
                        $errno = 0;
                        $errstr = '';
                        $start = microtime(true);
                        $stream = @stream_socket_client($target, $errno, $errstr, $timeout, STREAM_CLIENT_CONNECT, $context);
                        $conn_ms = round((microtime(true) - $start) * 1000, 1);

                        if (!$stream) {
                            $error_count++;
                            $insert_stmt->execute([
                                $check_domain, $domain_port, null, null, null, null,
                                null, 0, 0, null, null, null, 0, $conn_ms, 'error', "Connection failed: $errstr ($errno)"
                            ]);
                            $checks[] = [
                                'domain' => $check_domain,
                                'port' => $domain_port,
                                'status' => 'error',
                                'error' => "Connection failed: $errstr",
                                'connect_time_ms' => $conn_ms,
                            ];
                            continue;
                        }

                        $options = stream_context_get_options($context);
                        $cert = $options['ssl']['peer_certificate'] ?? null;

                        if (!$cert) {
                            $error_count++;
                            $insert_stmt->execute([
                                $check_domain, $domain_port, null, null, null, null,
                                null, 0, 0, null, null, null, 0, $conn_ms, 'error', 'No certificate presented'
                            ]);
                            fclose($stream);
                            $checks[] = [
                                'domain' => $check_domain,
                                'port' => $domain_port,
                                'status' => 'error',
                                'error' => 'No certificate presented',
                                'connect_time_ms' => $conn_ms,
                            ];
                            continue;
                        }

                        $cert_data = @openssl_x509_parse($cert, true);
                        fclose($stream);

                        if (!$cert_data) {
                            $error_count++;
                            $insert_stmt->execute([
                                $check_domain, $domain_port, null, null, null, null,
                                null, 0, 0, null, null, null, 0, $conn_ms, 'error', 'Failed to parse certificate'
                            ]);
                            $checks[] = [
                                'domain' => $check_domain,
                                'port' => $domain_port,
                                'status' => 'error',
                                'error' => 'Failed to parse certificate',
                                'connect_time_ms' => $conn_ms,
                            ];
                            continue;
                        }

                        $subject = $cert_data['subject'] ?? [];
                        $issuer = $cert_data['issuer'] ?? [];
                        $cn = $subject['CN'] ?? '';
                        $issuer_org = $issuer['O'] ?? ($issuer['CN'] ?? '');

                        $valid_from_ts = $cert_data['validFrom_time_t'] ?? null;
                        $valid_to_ts = $cert_data['validTo_time_t'] ?? null;
                        $now_ts = time();

                        $days_remaining = null;
                        $expired = false;
                        if ($valid_to_ts) {
                            $days_remaining = (int)ceil(($valid_to_ts - $now_ts) / 86400);
                            $expired = $now_ts > $valid_to_ts;
                        }

                        // SANs
                        $sans = [];
                        $extensions = $cert_data['extensions'] ?? [];
                        if (isset($extensions['subjectAltName'])) {
                            $parts = explode(',', $extensions['subjectAltName']);
                            foreach ($parts as $part) {
                                $part = trim($part);
                                if (preg_match('/^DNS:(.+)$/i', $part, $m)) $sans[] = $m[1];
                            }
                        }

                        $is_wildcard = (strpos($cn, '*') === 0);
                        $sig_algo = $cert_data['signatureTypeSN'] ?? $cert_data['signatureTypeLN'] ?? '';
                        $serial = $cert_data['serialNumber'] ?? '';

                        // Determine status
                        $status = 'valid';
                        if ($expired) {
                            $status = 'expired';
                            $expired_count++;
                        } elseif ($days_remaining !== null && $days_remaining <= $critical_days) {
                            $status = 'critical';
                            $expiring_count++;
                        } elseif ($days_remaining !== null && $days_remaining <= $warning_days) {
                            $status = 'warning';
                            $expiring_count++;
                        }

                        $insert_stmt->execute([
                            $check_domain, $domain_port, $cn, $issuer_org,
                            $valid_from_ts ? date('Y-m-d H:i:s', $valid_from_ts) : null,
                            $valid_to_ts ? date('Y-m-d H:i:s', $valid_to_ts) : null,
                            $days_remaining, $expired ? 1 : 0,
                            count($sans), json_encode($sans),
                            $sig_algo, (string)$serial,
                            $is_wildcard ? 1 : 0, $conn_ms,
                            $status, null
                        ]);

                        $checks[] = [
                            'domain' => $check_domain,
                            'port' => $domain_port,
                            'status' => $status,
                            'common_name' => $cn,
                            'issuer' => $issuer_org,
                            'days_remaining' => $days_remaining,
                            'expired' => $expired,
                            'valid_to' => $valid_to_ts ? date('Y-m-d', $valid_to_ts) : null,
                            'san_count' => count($sans),
                            'is_wildcard' => $is_wildcard,
                            'connect_time_ms' => $conn_ms,
                        ];
                    }

                    $result['checks'] = $checks;
                    $result['summary'] = [
                        'total_checked' => $checked_count,
                        'valid' => $checked_count - $error_count - $expired_count - $expiring_count,
                        'expiring' => $expiring_count,
                        'expired' => $expired_count,
                        'errors' => $error_count,
                    ];
                }
            }

            // --- report mode ---
            if (in_array($mode, ['report', 'check_report'])) {
                // Get latest check for each domain
                $latest = $pdo->query("
                    SELECT s.* FROM ssl_checks s
                    INNER JOIN (
                        SELECT domain, MAX(checked_at) as max_checked
                        FROM ssl_checks GROUP BY domain
                    ) latest ON s.domain = latest.domain AND s.checked_at = latest.max_checked
                    ORDER BY s.domain
                ")->fetchAll(PDO::FETCH_ASSOC);

                // Get domain list
                $domain_list = $pdo->query("SELECT domain, port, label, added_at FROM ssl_domains WHERE active = 1 ORDER BY domain")->fetchAll(PDO::FETCH_ASSOC);

                $report_entries = [];
                $expiring = [];
                $healthy = [];

                foreach ($latest as $row) {
                    $sans = [];
                    if ($row['sans']) {
                        $decoded = json_decode($row['sans'], true);
                        if (is_array($decoded)) $sans = $decoded;
                    }

                    $entry = [
                        'domain' => $row['domain'],
                        'port' => $row['port'],
                        'status' => $row['status'],
                        'common_name' => $row['common_name'],
                        'issuer' => $row['issuer_org'],
                        'days_remaining' => $row['days_remaining'],
                        'valid_to' => $row['valid_to'],
                        'expired' => (bool)$row['expired'],
                        'san_count' => $row['san_count'],
                        'connect_time_ms' => (float)$row['connect_time_ms'],
                        'checked_at' => $row['checked_at'],
                        'error_message' => $row['error_message'],
                    ];

                    $report_entries[] = $entry;

                    if ($row['status'] === 'valid') {
                        $healthy[] = $entry;
                    } else {
                        $expiring[] = $entry;
                    }
                }

                // Find domains in the list that haven't been checked yet
                $checked_domains = array_column($latest, 'domain');
                $unchecked = [];
                foreach ($domain_list as $d) {
                    if (!in_array($d['domain'], $checked_domains)) {
                        $unchecked[] = $d['domain'];
                    }
                }

                $result['report'] = [
                    'entries' => $report_entries,
                    'expiring_or_errored' => $expiring,
                    'healthy' => $healthy,
                    'unchecked' => $unchecked,
                    'monitored_domains' => array_column($domain_list, 'domain'),
                    'report_time' => date('Y-m-d H:i:s'),
                    'warning_threshold' => $warning_days,
                    'critical_threshold' => $critical_days,
                ];

                // Quick summary
                $total = count($report_entries);
                $good = count($healthy);
                $bad = count($expiring);
                $result['report']['summary'] = "{$total} domains monitored — {$good} healthy, {$bad} need attention";
            }

            // Store the summary in result
            return $result;
    }
}
